from elasticsearch import Elasticsearch
import json

# Initialize Elasticsearch client
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

def execute_dynamic_aggregation(index, script_code):
    """
    Execute dynamic aggregation script on Elasticsearch
    """
    try:
        # Validate script input
        if not script_code or not isinstance(script_code, str):
            raise ValueError("Invalid script code provided")
        
        # Build aggregation query with inline script
        query = {
            "aggs": {
                "dynamic_agg": {
                    "scripted_metric": {
                        "script": {
                            "inline": script_code
                        }
                    }
                }
            }
        }
        
        # Execute query
        response = es.search(index=index, body=query, request_cache=False)
        return response
        
    except Exception as e:
        raise Exception(f"Error executing aggregation: {str(e)}")

